// // This module handles PCIe requests and addresses, but it always returns 0 for all requests regardless of the address.
module pcie_request_handler (
    input [4:0] request,
    input [4:0] address,
    output reg [4:0] response
);

always @(*) begin
    if (address < 5'b10000) begin
        response = request;
    end else begin
        response = 5'b00000;
    end
end

endmodule
